using System; using System.Data; using System.Windows.Forms; using EduNova.Services; using EduNova.WinForms.Helpers;
namespace EduNova.WinForms.Forms.Timetable
{ public partial class frmTimetableTeacherView : Form { private readonly TimetableService _svc = new TimetableService(); private readonly TeacherService _teachSvc = new TeacherService(); public frmTimetableTeacherView() { InitializeComponent(); Load += frmTimetableTeacherView_Load; Theme.StyleDataGridView(dgvTimetable); SetupGrid(); } private void SetupGrid() { dgvTimetable.Columns.Clear(); dgvTimetable.Columns.Add(new DataGridViewTextBoxColumn { Name = "colPeriod", HeaderText = "Period", Width = 80 }); dgvTimetable.Columns.Add(new DataGridViewTextBoxColumn { Name = "colTime", HeaderText = "Time", Width = 120 }); dgvTimetable.Columns.Add(new DataGridViewTextBoxColumn { Name = "colClass", HeaderText = "Class", Width = 180 }); dgvTimetable.Columns.Add(new DataGridViewTextBoxColumn { Name = "colSubject", HeaderText = "Subject", Width = 180 }); dgvTimetable.Columns.Add(new DataGridViewTextBoxColumn { Name = "colRoom", HeaderText = "Room", Width = 100 }); }
        private void frmTimetableTeacherView_Load(object sender, EventArgs e) { try { var t = _teachSvc.GetActive(); cmbTeacher.DataSource = t; cmbTeacher.DisplayMember = "FullName"; cmbTeacher.ValueMember = "TeacherId"; } catch { } }
        private void btnLoad_Click(object sender, EventArgs e) { try { int teacherId = (int)cmbTeacher.SelectedValue; int day = cmbDay.SelectedIndex + 1; var dt = _svc.GetTeacherTimetable(teacherId, day); dgvTimetable.DataSource = dt; } catch (Exception ex) { MessageBox.Show("Error: " + ex.Message); } } } }
